/* 文件头注释：核心算法为逐位确定x的值，关键技术为位运算 */
#include <bits/stdc++.h>
using namespace std;

// 函数：根据y计算x
int findX(int y) {
    unsigned int x = 0; // 使用unsigned int避免符号位影响
    for (int i = 0; i < 32; ++i) {
        int bit = (y >> i) & 1;
        int prevBit = (i == 0) ? 0 : ((x >> (i - 1)) & 1); // 单独处理i=0的情况
        x |= (bit ^ prevBit) << i;
    }
    return static_cast<int>(x); // 转换为int输出
}

