/* 文件头注释：动态规划算法，用于判断是否可以通过选择每扇门的数字来达到目标军队人数 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, L, R;
    cin >> n >> L >> R;

    // 初始化dp数组，dp[i]表示是否可以达到人数i
    vector<bool> dp(R + 1, false);
    dp[1] = true; // 初始军队人数为1

    for (int i = 0; i < n; ++i) {
        int x, y;
        cin >> x >> y;

        // 使用临时数组new_dp来存储每次门选择后的新状态
        vector<bool> new_dp = dp;

        // 更新new_dp数组
        for (int j = 1; j <= R; ++j) {
            if (dp[j]) {
                if (j + x <= R) new_dp[j + x] = true;
                if (j + y <= R) new_dp[j + y] = true;
            }
        }

        // 将new_dp赋值给dp
        dp = new_dp;
    }

    // 检查是否有一个i在[L, R]范围内且dp[i]为true
    for (int i = L; i <= R; ++i) {
        if (dp[i]) {
            cout << "Yes" << endl;
            return 0;
        }
    }

    cout << "No" << endl;
    return 0;
}

